// teamC is where relationship counts are stored.
type teamC struct {
	BookingEntries      *int64
	EventTeamStandings  *int64
	ResultEntries       *int64
	SeasonTeamStandings *int64
	TeamDrivers         *int64
}

// PreloadCount sets a count in the C struct by name
func (o *Team) PreloadCount(name string, count int64) error {
	if o == nil {
		return nil
	}

	switch name {
	case "BookingEntries":
		o.C.BookingEntries = &count
	case "EventTeamStandings":
		o.C.EventTeamStandings = &count
	case "ResultEntries":
		o.C.ResultEntries = &count
	case "SeasonTeamStandings":
		o.C.SeasonTeamStandings = &count
	case "TeamDrivers":
		o.C.TeamDrivers = &count
	}
	return nil
}

