type teamJoins[Q dialect.Joinable] struct {
	typ                 string
	BookingEntries      modAs[Q, bookingEntryColumns]
	EventTeamStandings  modAs[Q, eventTeamStandingColumns]
	ResultEntries       modAs[Q, resultEntryColumns]
	SeasonTeamStandings modAs[Q, seasonTeamStandingColumns]
	TeamDrivers         modAs[Q, teamDriverColumns]
	CarModel            modAs[Q, carModelColumns]
	Season              modAs[Q, seasonColumns]
}

func (j teamJoins[Q]) aliasedAs(alias string) teamJoins[Q] {
	return buildTeamJoins[Q](buildTeamColumns(alias), j.typ)
}

func buildTeamJoins[Q dialect.Joinable](cols teamColumns, typ string) teamJoins[Q] {
	return teamJoins[Q]{
		typ: typ,
		BookingEntries: modAs[Q, bookingEntryColumns]{
			c: BookingEntries.Columns,
			f: func(to bookingEntryColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, BookingEntries.NameExpr().As(to.Alias())).On(
						to.TeamID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		EventTeamStandings: modAs[Q, eventTeamStandingColumns]{
			c: EventTeamStandings.Columns,
			f: func(to eventTeamStandingColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, EventTeamStandings.NameExpr().As(to.Alias())).On(
						to.TeamID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		ResultEntries: modAs[Q, resultEntryColumns]{
			c: ResultEntries.Columns,
			f: func(to resultEntryColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, ResultEntries.NameExpr().As(to.Alias())).On(
						to.TeamID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		SeasonTeamStandings: modAs[Q, seasonTeamStandingColumns]{
			c: SeasonTeamStandings.Columns,
			f: func(to seasonTeamStandingColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, SeasonTeamStandings.NameExpr().As(to.Alias())).On(
						to.TeamID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		TeamDrivers: modAs[Q, teamDriverColumns]{
			c: TeamDrivers.Columns,
			f: func(to teamDriverColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, TeamDrivers.NameExpr().As(to.Alias())).On(
						to.TeamID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		CarModel: modAs[Q, carModelColumns]{
			c: CarModels.Columns,
			f: func(to carModelColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, CarModels.NameExpr().As(to.Alias())).On(
						to.ID.EQ(cols.CarModelID),
					))
				}

				return mods
			},
		},
		Season: modAs[Q, seasonColumns]{
			c: Seasons.Columns,
			f: func(to seasonColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Seasons.NameExpr().As(to.Alias())).On(
						to.ID.EQ(cols.SeasonID),
					))
				}

				return mods
			},
		},
	}
}
